import{_ as d,o as e,c as a,a7 as r}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"en/guides/glossary.md","filePath":"en/guides/glossary.md","lastUpdated":1775394001000}'),h={name:"en/guides/glossary.md"};function i(o,t,n,s,l,b){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><p>A comprehensive glossary of terms used in Morimens (忘却前夜). Since the game was developed in Chinese, understanding the original terminology helps when reading community guides and discussion.</p><h2 id="characters" tabindex="-1">Characters <a class="header-anchor" href="#characters" aria-label="Permalink to &quot;Characters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>唤醒体</td><td>Awakener</td><td>游戏中可操控角色的统称，游走在疯狂边缘的人形武器</td></tr><tr><td>守密人</td><td>Keeper</td><td>玩家扮演的角色身份</td></tr></tbody></table><h2 id="game-systems" tabindex="-1">Game Systems <a class="header-anchor" href="#game-systems" aria-label="Permalink to &quot;Game Systems&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>灵啡肽</td><td>Menophine</td><td>体力/行动力系统，有可调上限。主线不消耗</td></tr><tr><td>灵知深化</td><td>Gnosis Enhancement</td><td>v1.1下半版本引入的系统，唤醒体等级上限提升至70级</td></tr><tr><td>界域</td><td>Realm / Domain</td><td>角色所属阵营类型：混沌、深海、血肉、超维。类似DBG中职业的概念</td></tr><tr><td>界域天赋</td><td>Realm Talent</td><td>运用相同界域的卡牌组合在一起时触发的职业效果</td></tr></tbody></table><h2 id="progression" tabindex="-1">Progression <a class="header-anchor" href="#progression" aria-label="Permalink to &quot;Progression&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>升格</td><td>Ascension / Promotion</td><td>突破角色等级上限的系统，首次在10级解锁</td></tr><tr><td>命轮</td><td>Wheel of Destiny</td><td>重复获取角色后可激活的额外能力，分R/SR/SSR品质</td></tr><tr><td>天赋</td><td>Talents</td><td>v1.5引入的额外被动能力树，现有角色可免费获得</td></tr><tr><td>密契</td><td>Sacred Covenant</td><td>提供额外角色增强与搭配思路的系统</td></tr></tbody></table><h2 id="combat" tabindex="-1">Combat <a class="header-anchor" href="#combat" aria-label="Permalink to &quot;Combat&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>刻印</td><td>Engravings</td><td>普通敌人击败后对卡牌附加额外效果</td></tr><tr><td>吞噬</td><td>Devour</td><td>血肉界域核心：消耗「胚」卡配合狂气爆发触发超强力效果</td></tr><tr><td>应急灵知体</td><td>Emergency Spirit Body</td><td>HP归零时消耗1个复活，恢复全状态，每场战斗最多5个</td></tr><tr><td>灵之觉醒牌</td><td>Spirit Awakening Card</td><td>每个唤醒体的特殊能力卡牌，区别于4张基础指令牌</td></tr><tr><td>狂气</td><td>Madness</td><td>角色通过出牌积累的能量，满后可释放狂气爆发</td></tr><tr><td>狂气爆发</td><td>Madness Burst</td><td>角色大招，狂气满后发动的强力技能</td></tr><tr><td>算力</td><td>Computation</td><td>使用卡牌时消耗的核心资源</td></tr><tr><td>胚</td><td>Embryo</td><td>血肉界域核心机制，胚融合达100%时获得「胚」卡片</td></tr><tr><td>触腕</td><td>Tentacle</td><td>深海界域核心机制，回合结束时自动攻击前排敌人</td></tr><tr><td>超维空间</td><td>Hyperdimension Space</td><td>超维界域核心机制，蓄积卡牌副本后进入额外超维回合</td></tr><tr><td>超限因果</td><td>Transcendence Causality</td><td>v1.5与超限爆发同时引入的新系统</td></tr><tr><td>超限爆发</td><td>Reproduction Frenzy</td><td>v1.5引入的新终极技能系统，部分角色可解锁</td></tr><tr><td>造物</td><td>Artifact / Relic</td><td>精英敌人击败后获得的特殊效果物品，分正面和负面</td></tr><tr><td>钥令</td><td>Key Order</td><td>守密人的独属能力，消耗银钥能量在战斗中发动</td></tr><tr><td>银钥共鸣</td><td>Silver Key Resonance</td><td>纯混沌编成时的特殊效果，每回合自动积攒250点银钥能量</td></tr><tr><td>银钥能量</td><td>Silver Key Energy</td><td>守密人的专属能量，用于发动钥令技能</td></tr></tbody></table><h2 id="community" tabindex="-1">Community <a class="header-anchor" href="#community" aria-label="Permalink to &quot;Community&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>御四家</td><td>Royal Four</td><td>四个核心混沌常驻角色（拉蒙娜、萝坦、朵尔、奥吉尔）的统称</td></tr><tr><td>深潜三杰</td><td>Deep Dive Trio</td><td>奥瑞塔、艾瑞卡、艾继丝的统称</td></tr><tr><td>节奏榜</td><td>Tier List</td><td>角色强度排行榜</td></tr></tbody></table><h2 id="装备" tabindex="-1">装备 <a class="header-anchor" href="#装备" aria-label="Permalink to &quot;装备&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>专造</td><td>Enlighten</td><td>角色专属武器装备</td></tr></tbody></table><h2 id="素材" tabindex="-1">素材 <a class="header-anchor" href="#素材" aria-label="Permalink to &quot;素材&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>委托密函</td><td>Commission Secret Letter</td><td>通过密函线索兑换的角色专属委托，挑战关卡获得角色碎片</td></tr><tr><td>密函</td><td>Secret Letter</td><td>角色碎片获取途径，通过日常副本收集密函线索兑换</td></tr><tr><td>灵知制剂</td><td>Gnosis Primer</td><td>用于提升角色等级的经验材料</td></tr></tbody></table><h2 id="世界观" tabindex="-1">世界观 <a class="header-anchor" href="#世界观" aria-label="Permalink to &quot;世界观&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>弥萨格大学</td><td>Mythag University</td><td>为数不多知晓融蚀真相的组织，玩家所属核心机构</td></tr><tr><td>融蚀</td><td>Dissolution</td><td>数百年前降临的灾厄，抹灭生命、理智、记忆中一切有意义之物</td></tr></tbody></table><h2 id="玩法" tabindex="-1">玩法 <a class="header-anchor" href="#玩法" aria-label="Permalink to &quot;玩法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>幻梦深潜</td><td>Psyche Deepdive</td><td>特殊探索玩法模式</td></tr><tr><td>无光秘境</td><td>Lightless Realm</td><td>解锁角色升星的挑战副本，也可通过通关主线章节解锁</td></tr><tr><td>相位</td><td>Traphase</td><td>PVP对战模式（相位对弈）</td></tr><tr><td>融灾</td><td>Dissolution</td><td>高难度战斗挑战模式（融灾禁区），完成主线5-4解锁，每两周刷新</td></tr></tbody></table><h2 id="社交" tabindex="-1">社交 <a class="header-anchor" href="#社交" aria-label="Permalink to &quot;社交&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>助战</td><td>Support / Friend Unit</td><td>借用其他玩家角色参与战斗</td></tr></tbody></table><h2 id="货币" tabindex="-1">货币 <a class="header-anchor" href="#货币" aria-label="Permalink to &quot;货币&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>无垢之芯</td><td>Pure Core</td><td>常驻池/武器池抽卡道具</td></tr><tr><td>流明之芯</td><td>Luminous Core</td><td>限定池抽卡道具</td></tr><tr><td>金币</td><td>Gold Coins</td><td>每日副本获得的通用货币</td></tr><tr><td>银芯</td><td>Silver</td><td>游戏基础货币</td></tr></tbody></table><h2 id="抽卡" tabindex="-1">抽卡 <a class="header-anchor" href="#抽卡" aria-label="Permalink to &quot;抽卡&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>灵识黑潮</td><td>Standard Banner</td><td>常驻唤醒池</td></tr></tbody></table><h2 id="剧情" tabindex="-1">剧情 <a class="header-anchor" href="#剧情" aria-label="Permalink to &quot;剧情&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Chinese</th><th>English</th><th>Description</th></tr></thead><tbody><tr><td>忘却篇</td><td>Oblivion Chapter</td><td>主线第一大篇章，序章至第五章</td></tr><tr><td>星辰篇</td><td>Stellar Chapter</td><td>主线第二大篇章，v2.0「星辰正位之刻」开启</td></tr><tr><td>融灾黑潮</td><td>Erosion Black Tide</td><td>后期章节特殊负面效果机制，施加「狂气衰竭」「银钥振荡」等debuff</td></tr></tbody></table><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../systems/">Game Systems</a></li><li><a href="./../modes/combat.html">Combat</a></li><li><a href="./beginner.html">Beginner Guide</a></li></ul>',30)])])}const u=d(h,[["render",i]]);export{m as __pageData,u as default};
